import { lerp, clamp, ease } from "./helpers";
export const RX = 36;
export const RY = 26;

export default function HeroCard({ card, progress }) {
  const rad = (card.angle * Math.PI) / 180;
  const ox = Math.cos(rad) * RX;
  const oy = -Math.sin(rad) * RY;
  const mag = Math.sqrt(ox*ox+oy*oy)||1;
  const EX = (ox/mag)*130, EY = (oy/mag)*130;
  const t = ease(clamp((progress-0.35)/0.55,0,1));
  const tx = lerp(ox,EX,t), ty = lerp(oy,EY,t);
  const opacity = lerp(1,0,clamp((progress-0.65)/0.3,0,1));

  return (
    <div style={{
      position:"absolute",
      left:`calc(50% + ${tx}vw)`,top:`calc(50% + ${ty}vh)`,
      transform:`translate(-50%,-50%) rotate(${card.rotate}deg)`,
      opacity,zIndex:card.z,willChange:"transform,opacity",pointerEvents:"none",
    }}>
      <div style={{
        width:160,height:200,background:"#f0eeeb",borderRadius:14,
        overflow:"hidden",boxShadow:"0 12px 40px rgba(0,0,0,0.35), 0 2px 8px rgba(0,0,0,0.2)",
        display:"flex",flexDirection:"column",position:"relative",
      }}>
        <div style={{
          flex:1,
          background:"linear-gradient(135deg,#d0cdc8 0%,#b8b4ae 40%,#a0a09a 100%)",
          position:"relative",overflow:"hidden",
          display:"flex",alignItems:"center",justifyContent:"center",
        }}>
          <div style={{
            position:"absolute",width:"100%",height:"100%",
            backgroundImage:`
              radial-gradient(ellipse 60px 40px at 60% 65%,#888 0%,transparent 100%),
              radial-gradient(ellipse 30px 50px at 30% 40%,#666 0%,transparent 100%),
              linear-gradient(180deg,transparent 40%,#999 100%)
            `,
          }}/>
          <div style={{position:"absolute",top:10,left:10,width:12,height:12,borderRadius:"50%",background:"#e53e3e"}}/>
          <div style={{
            position:"absolute",bottom:14,right:14,width:0,height:0,
            borderLeft:"10px solid transparent",borderRight:"10px solid transparent",borderBottom:"18px solid #3b5bdb",
          }}/>
          <div style={{position:"absolute",bottom:0,left:0,right:0,height:"45%",background:"linear-gradient(180deg,transparent,#555)"}}/>
          <div style={{position:"absolute",bottom:4,left:8,right:8,height:30,borderRadius:4,background:"rgba(60,60,60,0.7)"}}/>
        </div>
        <div style={{padding:"8px 10px",background:"#f0eeeb",borderTop:"1px solid #ddd"}}>
          <div style={{width:"80%",height:5,borderRadius:3,background:"#ccc",marginBottom:5}}/>
          <div style={{width:"60%",height:5,borderRadius:3,background:"#ddd",marginBottom:4}}/>
          <div style={{fontSize:8,color:"#888",fontFamily:"monospace",letterSpacing:0.3}}>{card.label}</div>
        </div>
      </div>
    </div>
  );
}
